import React from 'react';
import { GoogleMap, LoadScript, Marker } from '@react-google-maps/api';

const mapContainerStyle = {
  width: '100%',
  height: '400px'
};

const defaultCenter = {
  lat: 15.8929, // Placeholder coordinates (can center on the municipality)
  lng: 73.8224
};

const MapPanel = ({ logs }) => {
  return (
    <LoadScript googleMapsApiKey={process.env.REACT_APP_GOOGLE_MAPS_API_KEY}>
      <GoogleMap
        mapContainerStyle={mapContainerStyle}
        zoom={13}
        center={defaultCenter}
      >
        {logs.map((log) => (
          <Marker
            key={log.id}
            position={{ lat: log.lat, lng: log.lng }}
            icon={log.anomaly_flag === 1 ? "http://maps.google.com/mapfiles/ms/icons/red-dot.png" : "http://maps.google.com/mapfiles/ms/icons/green-dot.png"}
            title={`Worker ${log.worker_id} - ${new Date(log.timestamp).toLocaleTimeString()}`}
          />
        ))}
      </GoogleMap>
    </LoadScript>
  );
};

export default MapPanel;
